<template>
	<view class="body">
		<u-navbar :z-index="980" :is-back="true" :custom-back="toUcenter" title="我的余额"></u-navbar>
		<scroll-view class="scroll-box" scroll-y @scrolltolower="reachBottom" :style="{height:scrollHeight+'px'}">
			<view class="my-wallet" :style="{
				backgroundImage:'url('+$util.img('/statics/uni/img/wallet_img_bg.png')+')'
			}">
				<view class="wallet-box" :style="{
				backgroundImage:'url('+$util.img('/statics/uni/img/wallet_img_kapian.png')+')'
			}">
					<view class="top">
						<view class="item">
							<view class="label">
								账户余额
							</view>
							<view class="value">
								{{balance}}
							</view>
						</view>
						<view class="btn" @click="$util.on('/pages/ucenter_sub/recharge')">
							充值
						</view>
					</view>
					<view class="bottom">
						<view class="item">
							<view class="label">
								本月消费
							</view>
							<view class="value">
								{{money_month}}
							</view>
						</view>
						<view class="item">
							<view class="label">
								总消费
							</view>
							<view class="value">
								{{money_month1}}
							</view>
						</view>
					</view>
				</view>

				<view class="wallet-list">

					<view class="title">
						<view class="item active">
							余额明细
						</view>
					</view>


					<view class="box-list">
						<view class="item" v-for="(item,index) in list" :key="index" @click="toOrder(item)">
							<view class="item-title">
								<view class="label">
									{{item.trade_type_text}}
								</view>
								<view v-if="item.ordersn && item.order_id" @click.stop="paste(item.ordersn)">
									{{item.ordersn}}
								</view>
								<view class="time">
									{{$util.timeFormat(item.create_time,"yyyy-mm-dd hh:MM:ss")}}
								</view>
							</view>

							<view class="item-money">
								{{item.change_type == 1?'+'+item.money:'-'+item.money}}
							</view>
						</view>
						<u-empty v-if="loaded &&  list.length == 0"></u-empty>
					</view>
				</view>
				<u-loadmore :status="loadStatus" margin-top="20" icon-type="circle" v-if="list.length >0 && loaded" />

			</view>

		</scroll-view>
	</view>
</template>


<script>
	import {
		mapGetters
	} from 'vuex'
	export default {
		data() {
			return {
				sys: this.$util.sys(),
				page: 1,
				limit: 10,

				balance: '0.00',
				money_month: '0.00',
				money_month1: '0.00',

				list: [],
				loaded: false,
				loadStatus: 'loadmore',
				type: 1,
			}
		},
		computed: {
			...mapGetters(['deviceInfo']),
			scrollHeight() {
				return this.deviceInfo.screenHeight - 44
			}
		},
		onShow() {},
		onLoad() {
			this.loadData();
			this.loadDataList()
		},

		methods: {
			async loadData() {
				// this.loading = true;
				uni.showLoading({
					mask: true,
					title: '加载中...'
				})
				let params = {};
				await this.$u.api.walletConfig(params)
					.then(res => {
						// this.bg = res.bg
						// this.kapian = res.kapian
						this.balance = res.balance
						this.money_month = res.money_month
						this.money_month1 = res.money_month1

					}).catch(res => {})

				// this.loading = false;
				uni.hideLoading()

			},
			toOrder(item) {
				if (item.order_id) {
					this.$util.on('/pages/order/info?id=' + item.order_id)
				}
			},
			paste(val, type, order) {
				if (!val) {
					val = '';
				}

				//充值信息
				if (type == 1) {
					for (let i = 0; i < order.cards.length; i++) {

						if (order.cards[i].card_no && order.cards[i].card_no != '') {
							val += order.cards[i].card_no + ' ' + order.cards[i]
								.card_password + "\r\n"
						} else {
							val += order.cards[i].card_password + "\r\n"
						}
					}

					// #ifdef H5
					window._agl && window._agl.push(['track', ['success', {
						t: 1
					}]])
					// #endif

				} else if (type == 2 && order.recharge_info) {

					for (let i = 0; i < order.recharge_info.length; i++) {
						val += order.recharge_info[i].v + "\r\n"
					}
				}
				if (val) {
					val = val.replace(/<br>/ig, '\r\n');
					val = val.replace(/(^\s*)|(\s*$)/g, "");
					val = val.replace(/&amp;/ig, '&');
				}

				uni.setClipboardData({
					data: val + '',
					success: function() {
						uni.showToast({
							title: '复制成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					}
				})
			},
			// 页面数据
			async loadDataList() {


				await this.$u.api.walletList({
						type: this.type,
						keyword: this.keyword,
						page: this.page,
						limit: this.limit,
					})
					.then(res => {
						if (res.list.length == 0) {
							this.loadStatus = 'nomore'
						} else {
							if (this.list.length > 0) {
								this.list = this.list.concat(res.list)

							} else {
								this.list = res.list

							}

							if (res.list.length < this.limit) {
								this.loadStatus = 'nomore'
							} else {
								this.loadStatus = 'loadmore'
							}


							this.page++
						}
					}).catch(res => {})

				this.loaded = true;
				//loaded新字段用于表示数据加载完毕，如果为空可以显示空白页

				// console.log(item	);
			},
			reachBottom() {

				console.log(1231);
				setTimeout(() => {
					this.loadDataList();
				}, 200);

			},

			toUcenter() {
				this.$Router.push({
					path: '/pages/ucenter/index'
				})
			},
		}

	}
</script>

